import { z } from 'zod';

/**
 * Base User Schema
 */
export const UserSchema = z.preprocess(
  (data: unknown) => {
    if (!data || typeof data !== 'object') return data;
    const d = data as Record<string, unknown>;
    const out: Record<string, unknown> = { ...d };
    if ('active' in d && !('isActive' in d)) out.isActive = d.active;
    if (!out.fullName && (out.firstName || out.lastName))
      out.fullName = [out.firstName, out.lastName].filter(Boolean).join(' ');
    if (out.role && (!Array.isArray(out.roles) || (out.roles as unknown[]).length === 0))
      out.roles = [out.role];
    return out;
  },
  z.object({
    id: z.union([z.string(), z.number()]).transform(v => String(v)),
    email: z.string().optional().nullable(),
    role: z.string().optional().nullable(),
    fullName: z.string().optional().nullable(),
    firstName: z.string().optional().nullable(),
    middleName: z.string().optional().nullable(),
    lastName: z.string().optional().nullable(),
    phoneNumber: z.string().optional().nullable(),
    employeeID: z.string().optional().nullable(),
    enrollmentId: z.string().optional().nullable(),
    collegeName: z.string().optional().nullable(),
    otpEnabled: z.boolean().optional().nullable(),
    userProfileId: z.union([z.string(), z.number()]).optional().nullable().transform(v => v ? String(v) : v),
    userId: z.union([z.string(), z.number()]).optional().nullable().transform(v => v ? String(v) : v),
    name: z.string().optional().nullable(),
    isActive: z.boolean().optional().nullable(),
    profilePictureUrl: z.string().optional().nullable(),
    profilePictureVersion: z.number().optional().nullable(),
    joiningDate: z.string().optional().nullable(),
    birthDate: z.string().optional().nullable(),
    leavingDate: z.string().optional().nullable(),
    pan: z.string().optional().nullable(),
    roles: z.array(z.string()).default([]),
  })
);

/**
 * Role Schema
 */
export const RoleSchema = z.object({
  id: z.string(),
  name: z.string(),
  description: z.string().optional().nullable(),
  active: z.boolean().optional(),
  isBuiltIn: z.boolean().optional(),
  userCount: z.number().optional(),
  permissionCount: z.number().optional(),
});

export const LoginPayloadSchema = z.object({
  email: z.string().email("Invalid email address"),
  password: z.string().min(1, "Password is required"),
  rememberMe: z.boolean().optional(),
});

/**
 * Login Response Schema
 */
export const LoginResponseSchema = z.object({
  email: z.string().email(),
  roles: z.array(z.string()).default([]),
  token: z.string(),
  firstName: z.string().optional(),
  fullName: z.string().optional(),
  id: z.string().optional(),
  profilePictureVersion: z.number().optional().nullable(),
});

/**
 * Application Setting Schema
 */
export const AppSettingSchema = z.object({
  id: z.string(),
  key: z.string(),
  value: z.string().nullable().optional(),
  category: z.string().nullable(),
  description: z.string().optional().nullable(),
  isEncrypted: z.boolean().optional(),
  isReadOnly: z.boolean().optional(),
  isOptimistic: z.boolean().optional(),
});

/**
 * Paginated Response Schema Helper
 */
export const PaginatedSchema = <T extends z.ZodTypeAny>(dataSchema: T) =>
  z.object({
    pageIndex: z.number(),
    pageSize: z.number(),
    totalCount: z.number(),
    totalPages: z.number(),
    hasNextPage: z.boolean(),
    hasPreviousPage: z.boolean(),
    data: z.array(dataSchema),
  });

/**
 * Work Schedule Schema
 */
export const WorkDaySchema = z.object({
  date: z.string(),
  dayType: z.string(),
  shiftType: z.string().nullable(),
  workDescription: z.string().nullable(),
  isEditable: z.boolean(),
});

export const WorkScheduleResponseSchema = z.object({
  id: z.string(),
  year: z.number(),
  month: z.number(),
  status: z.string(),
  reviewNotes: z.string().optional().nullable(),
  days: z.array(WorkDaySchema),
  userId: z.string().optional().nullable(),
  userFullName: z.string().optional().nullable(),
  userProfile: z.object({
    id: z.string(),
    firstName: z.string().optional().nullable(),
    fullName: z.string().optional().nullable(),
    email: z.string().optional().nullable(),
  }).optional().nullable(),
});
